let tracePayload = {};
let triggerBody = {};
try {
  const triggerJson = $node['Webhook Trigger']?.json || {};
  triggerBody = triggerJson.body || triggerJson;
  tracePayload = {
    agent_run_id: triggerBody.agent_run_id || null,
    agent_event_callback_url: triggerBody.agent_event_callback_url || null,
    agent_trace: triggerBody.agent_trace || null,
    callbackBaseUrl: triggerBody.callbackBaseUrl || triggerBody.callback_base_url || null,
  };
} catch (error) {
  tracePayload = {};
}

// Normalize Google Contacts node output into lead format
// The Google Contacts node returns individual contact items via $input.all()
const allItems = $input.all();
const leads = [];

for (const item of allItems) {
  const person = item.json;
  const names = person.names || [];
  const emails = person.emailAddresses || [];
  const phones = person.phoneNumbers || [];
  const orgs = person.organizations || [];
  const locations = person.locations || [];

  const name = names[0]?.displayName || '';
  if (!name || name.length < 2) continue;

  const email = emails[0]?.value || '';
  const phone = phones[0]?.value || '';
  const company = orgs[0]?.name || '';
  const jobTitle = orgs[0]?.title || '';
  const location = locations[0]?.value || '';

  if (!email && !company && !jobTitle) continue;

  leads.push({
    name,
    email: email || undefined,
    company: company || undefined,
    job_title: jobTitle || undefined,
    phone_number: phone || undefined,
    location: location || undefined,
    lead_source: 'warm_google_contacts',
    warm_source_detail: 'Google Contacts sync',
  });
}

return [{ json: { leads, count: leads.length, is_test_data: triggerBody.is_test_data === true || triggerBody.mode === 'smoke' || triggerBody.run_mode === 'smoke', mode: triggerBody.mode || triggerBody.run_mode || null, ...tracePayload } }];

const timestamp = Date.now();
return [{ json: {
  names: [{ displayName: 'ATAS Production Google Smoke Lead ' + timestamp }],
  emailAddresses: [{ value: 'wrm-production-google-smoke-' + timestamp + '@example.com' }],
  phoneNumbers: [{ value: '+15550000000' }],
  organizations: [{ name: 'Synthetic Production Smoke Company', title: 'Synthetic Smoke Tester' }],
  locations: [{ value: 'Synthetic City' }],
  smoke_marker: 'wrm-002-production-smoke',
  is_test_data: true,
} }];
